}

function normalizeApiMetricPath(pathValue) {
  const raw = String(pathValue || '').split('?')[0].trim();
  if (!raw) return '/';
  return raw
    .replace(/\/\d+(?=\/|$)/g, '/:id')
    .replace(/\/[0-9a-f]{8}-[0-9a-f-]{13,}(?=\/|$)/gi, '/:uuid')
